#include <batteries/async/toggle.hpp>
//

#include <batteries/int_types.hpp>
#include <batteries/optional.hpp>

#include <benchmark/benchmark.h>

#include <memory>
#include <random>
#include <shared_mutex>
#include <thread>
#include <unordered_map>

namespace {

using namespace batt::int_types;

using batt::None;
using batt::Optional;

constexpr usize kNumWriterThreads = 1;
constexpr usize kNumRefresh = 2500;
constexpr usize kMinOpCount = usize{1} << 24;
constexpr usize kMaxOpCount = usize{1} << 24;

class AsyncToggleScalabililty : public ::benchmark::Fixture
{
   public:
    void SetUp(::benchmark::State& state) override
    {
        this->n_ops = state.range(0);
        this->refresh_every_n = this->n_ops / kNumRefresh;
    }

    void TearDown(::benchmark::State& state [[maybe_unused]]) override
    {
    }

    //----- --- -- -  -  -   -

    template <typename Rng, typename Dist>
    void make_new_map(Rng& rng, Dist& pick_key, usize n_items, std::unordered_map<u64, u64>& map_out)
    {
        map_out.clear();
        for (usize item_i = 0; item_i < n_items; ++item_i) {
            map_out[pick_key(rng)] = item_i;
        }
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    usize n_ops = 0;
    usize refresh_every_n = 0;
    std::shared_mutex shared_mutex;
    std::shared_ptr<std::unordered_map<u64, u64>> shared_map;
    batt::Toggle<std::unordered_map<u64, u64>> toggle;
};

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
BENCHMARK_DEFINE_F(AsyncToggleScalabililty, BattToggle)(benchmark::State& state)
{
    const bool is_writer = state.thread_index() < kNumWriterThreads;
    std::default_random_engine rng{/*seed=*/(u32)state.thread_index()};
    std::uniform_int_distribution<u64> pick_key{0, 9999};

    if (is_writer) {
        batt::Toggle<std::unordered_map<u64, u64>>::Writer writer{this->toggle};
        this->make_new_map(rng, pick_key, this->refresh_every_n, writer.new_value());
    }

    for (auto _ : state) {
        if (is_writer) {
            for (usize refresh_i = 0; refresh_i < kNumRefresh; ++refresh_i) {
                batt::Toggle<std::unordered_map<u64, u64>>::Writer writer{this->toggle};
                this->make_new_map(rng, pick_key, this->refresh_every_n, writer.new_value());
            }
        } else {
            for (usize op_i = 0; op_i < this->n_ops; ++op_i) {
                batt::Toggle<std::unordered_map<u64, u64>>::Reader reader{this->toggle};

                u64 key = pick_key(rng);
                auto iter = reader->find(key);

                benchmark::DoNotOptimize(iter);
            }
        }
    }
}

BENCHMARK_REGISTER_F(AsyncToggleScalabililty, BattToggle)
    ->ThreadRange(1 + kNumWriterThreads, std::thread::hardware_concurrency())
    ->Range(kMinOpCount, kMaxOpCount);

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
BENCHMARK_DEFINE_F(AsyncToggleScalabililty, RWLock)(benchmark::State& state)
{
    const bool is_writer = state.thread_index() < kNumWriterThreads;
    std::default_random_engine rng{/*seed=*/(u32)state.thread_index()};
    std::uniform_int_distribution<u64> pick_key{0, 9999};

    if (is_writer) {
        this->shared_map = std::make_shared<std::unordered_map<u64, u64>>();
        this->make_new_map(rng, pick_key, this->refresh_every_n, *this->shared_map);
    }

    for (auto _ : state) {
        if (is_writer) {
            for (usize refresh_i = 0; refresh_i < kNumRefresh; ++refresh_i) {
                auto next_map = std::make_shared<std::unordered_map<u64, u64>>();
                this->make_new_map(rng, pick_key, this->refresh_every_n, *next_map);
                {
                    std::unique_lock<std::shared_mutex> wr_lock{this->shared_mutex};
                    this->shared_map = std::exchange(next_map, nullptr);
                }
            }
        } else {
            for (usize op_i = 0; op_i < this->n_ops; ++op_i) {
                std::shared_ptr<const std::unordered_map<u64, u64>> local_map;
                {
                    std::shared_lock<std::shared_mutex> rd_lock{this->shared_mutex};
                    local_map = this->shared_map;
                }

                u64 key = pick_key(rng);
                auto iter = local_map->find(key);

                benchmark::DoNotOptimize(iter);
            }
        }
    }
}

BENCHMARK_REGISTER_F(AsyncToggleScalabililty, RWLock)
    ->ThreadRange(1 + kNumWriterThreads, std::thread::hardware_concurrency())
    ->Range(kMinOpCount, kMaxOpCount);

}  //namespace
